 44→function slugify(text: string): string {
 45→  return text
 46→    .toLowerCase()
 47→    .normalize('NFD')
 48→    .replace(/[\u0300-\u036f]/g, '')
 49→    .replace(/[^a-z0-9]+/g, '-')
 50→    .replace(/^-+|-+$/g, '')
 51→    .slice(0, 60);
 52→}
