 63→class LogBuffer {
 64→  private buf: string[] = [];
 65→  private timer: ReturnType<typeof setInterval> | null = null;
 66→  private path: string;
 67→
 68→  constructor(
 69→    initialPath: string,
 70→    private readonly flushMs: number,
 71→  ) {
 72→    this.path = initialPath;
 73→    this.timer = setInterval(() => this.flush(), this.flushMs);
 74→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
 75→      (this.timer as NodeJS.Timeout).unref();
 76→    }
 77→  }
 78→
 79→  write(raw: string): void {
 80→    this.buf.push(stripAnsi(raw));
 81→  }
 82→
 83→  flush(): void {
 84→    if (this.buf.length === 0) return;
 85→    const chunk = this.buf.join('');
 86→    this.buf.length = 0;
 87→    try {
 88→      appendFileSync(this.path, chunk);
 89→    } catch (err) {
 90→      console.error(`[LogBuffer] write failed: ${err}`);
 91→    }
 92→  }
 93→
 94→  startNewFile(newPath: string): void {
 95→    this.flush();
 96→    this.path = newPath;
 97→  }
 98→
 99→  renameFile(newPath: string): void {
100→    this.flush();
101→    try {
102→      renameSync(this.path, newPath);
103→      this.path = newPath;
104→    } catch {}
105→  }
106→
107→  currentPath(): string {
108→    return this.path;
109→  }
110→
111→  dispose(): void {
112→    if (this.timer) clearInterval(this.timer);
113→    this.flush();
114→  }
115→}
