      'claude',
      '-p',
      TASK_PROMPT,
      '--verbose',
      '--debug',
      '--dangerously-skip-permissions',
      '--output-format',
      'stream-json',
      '--include-partial-messages',
      '--model=opus',
    ],
    {
      cwd: process.cwd(),
      env: process.env,
      stdout: 'pipe',
      stderr: 'inherit',
