514→function printHeader(): void {
515→  println();
516→  println('==========================================', 'blue');
517→  println('   Ralph Loop - Bun.js Edition', 'blue');
518→  println('==========================================', 'blue');
519→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
520→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
521→  println(
522→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
523→  );
524→  println(
