 65→const hooks = {
 66→  loopStart: new AsyncSeriesHook<[typeof CONFIG]>(['config']),
 67→  iterationStart: new AsyncSeriesHook<[IterationContext]>(['context']),
 68→  iterationSuccess: new AsyncSeriesHook<[IterationResult, IterationContext]>([
 69→    'result',
 70→    'context',
 71→  ]),
 72→  iterationTimeout: new SyncHook<[IterationResult, IterationContext]>([
 73→    'result',
 74→    'context',
 75→  ]),
 76→  iterationFailure: new AsyncSeriesHook<[IterationResult, FailureContext]>([
 77→    'result',
 78→    'context',
 79→  ]),
 80→  statusParsed: new SyncWaterfallHook<[RalphStatus | null, string]>([
 81→    'status',
 82→    'output',
 83→  ]),
 84→  taskComplete: new AsyncSeriesHook<[RalphStatus, IterationContext]>([
 85→    'status',
 86→    'context',
 87→  ]),
 88→  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
 89→    'status',
 90→    'totalIterations',
 91→  ]),
 92→  backoff: new SyncBailHook<[BackoffContext], boolean>(['context']),
 93→  loopEnd: new SyncHook<[number]>(['totalIterations']),
 94→  cleanup: new SyncHook<[string]>(['signal']),
 95→};
