 99→function slugify(text: string): string {
100→  return text
101→    .toLowerCase()
102→    .normalize('NFD')
103→    .replace(/[\u0300-\u036f]/g, '')
104→    .replace(/[^a-z0-9]+/g, '-')
105→    .replace(/^-+|-+$/g, '')
106→    .slice(0, 60);
107→}
108→
109→function logTimestamp(): string {
110→  const d = new Date();
111→  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
112→}
113→
114→function logFilePath(slug: string): string {
115→  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
116→}
117→
118→class LogBuffer {
119→  private buf: string[] = [];
120→  private timer: ReturnType<typeof setInterval> | null = null;
121→  private path: string;
122→
123→  constructor(
124→    initialPath: string,
125→    private readonly flushMs: number,
126→  ) {
127→    this.path = initialPath;
128→    this.timer = setInterval(() => this.flush(), this.flushMs);
129→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
130→      (this.timer as NodeJS.Timeout).unref();
131→    }
132→  }
133→
134→  write(raw: string): void {
135→    this.buf.push(stripAnsi(raw));
136→  }
137→
138→  flush(): void {
139→    if (this.buf.length === 0) return;
140→    const chunk = this.buf.join('');
141→    this.buf.length = 0;
142→    try {
143→      appendFileSync(this.path, chunk);
144→    } catch (err) {
145→      console.error(`[LogBuffer] write failed: ${err}`);
146→    }
147→  }
148→
149→  startNewFile(newPath: string): void {
150→    this.flush();
151→    this.path = newPath;
152→  }
153→
154→  renameFile(newPath: string): void {
155→    this.flush();
156→    try {
157→      renameSync(this.path, newPath);
158→      this.path = newPath;
159→    } catch {}
160→  }
161→
162→  currentPath(): string {
163→    return this.path;
164→  }
165→
166→  dispose(): void {
167→    if (this.timer) clearInterval(this.timer);
168→    this.flush();
169→  }
170→}
171→
172→const logBuffer = new LogBuffer(
173→  logFilePath('startup'),
174→  CONFIG.logFlushInterval,
175→);
