265→interface StreamMessage {
266→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
267→  subtype?: string;
268→  role?: 'assistant' | 'user';
269→  event?: {
270→    type: string;
271→    delta?: {
272→      type: string;
273→      text?: string;
274→    };
275→  };
