290→function parseRalphStatus(output: string): RalphStatus | null {
291→  const marker = output.lastIndexOf('RALPH_STATUS:');
292→  if (marker === -1) return null;
293→
294→  const jsonStart = output.indexOf('{', marker);
295→  if (jsonStart === -1) return null;
296→
297→  let depth = 0;
298→  for (let i = jsonStart; i < output.length; i++) {
299→    if (output[i] === '{') depth++;
300→    if (output[i] === '}') depth--;
301→    if (depth === 0) {
302→      try {
303→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
304→        if (typeof parsed.exit === 'boolean') {
305→          return parsed as RalphStatus;
306→        }
307→      } catch {}
308→      return null;
309→    }
310→  }
311→  return null;
312→}
