  1→#!/usr/bin/env bun
  2→
  3→/**
  4→ * Ralph Loop - Automated Claude Code Task Executor
  5→ *
  6→ * Based on Geoffrey Huntley's Ralph Wiggum technique:
  7→ * - Fresh context per iteration (new Claude instance each time)
  8→ * - Memory persists through files only (git, progress.txt)
  9→ * - One task per iteration
 10→ * - Completion signal terminates loop
 11→ *
 12→ * Uses Claude CLI's --output-format stream-json for real-time streaming.
 13→ *
 14→ * @see https://ghuntley.com/ralph/
 15→ */
 16→
 17→import { appendFileSync, mkdirSync, renameSync } from 'node:fs';
 18→import { chalk } from 'zx';
 19→import {
 20→  AsyncSeriesHook,
 21→  SyncHook,
 22→  SyncWaterfallHook,
 23→  SyncBailHook,
 24→} from 'tapable';
 25→
 26→const ANSI_REGEX = /\x1B\[[0-9;]*m/g;
 27→const stripAnsi = (s: string): string => s.replace(ANSI_REGEX, '');
 28→
 29→function parsePositiveInt(arg: string | undefined, fallback: number): number {
 30→  const parsed = parseInt(arg ?? String(fallback), 10);
 31→  if (isNaN(parsed) || parsed <= 0) {
 32→    console.error(`Error: expected a positive integer, got "${arg}"`);
 33→    process.exit(1);
 34→  }
 35→  return parsed;
 36→}
 37→
 38→const LOG_DIR = './.loop';
 39→mkdirSync(LOG_DIR, { recursive: true });
 40→
 41→const CONFIG = Object.freeze({
 42→  maxIterations: parsePositiveInt(Bun.argv[2], 100),
 43→  delayBetweenIterations: 1_000,
 44→  progressFile: './.claude/progress.txt',
 45→  iterationTimeout: 600_000,
 46→  logFlushInterval: 2_000,
 47→  exitPattern: /RALPH_STATUS:\s*\{[^}]*"exit":\s*true[^}]*\}/,
 48→});
 49→
 50→interface IterationResult {
 51→  output: string;
 52→  exitCode: number;
 53→  timedOut: boolean;
 54→}
 55→
 56→interface RalphStatus {
 57→  exit: boolean;
 58→  task: string;
 59→  remaining: number;
 60→}
 61→
 62→interface IterationContext {
 63→  iteration: number;
 64→  maxIterations: number;
 65→  logPath: string;
 66→}
 67→
 68→interface FailureContext extends IterationContext {
 69→  exitCode: number;
 70→  consecutiveFailures: number;
 71→}
 72→
 73→interface BackoffContext extends FailureContext {
 74→  backoffMs: number;
 75→}
 76→
 77→/**
 78→ * Tapable hooks for the Ralph Loop lifecycle.
 79→ *
 80→ * Hook contracts:
 81→ * - `resolveStatus` (SyncWaterfallHook): Taps MUST return `RalphStatus | null`.
 82→ *   Only the first argument (status) is waterfalled; the second (output) is read-only context.
 83→ * - `shouldSkipBackoff` (SyncBailHook): Return `true` to skip backoff. Return `undefined`
 84→ *   to defer to the next tap. Do NOT return `false` — it short-circuits without skipping.
 85→ * - `cleanup` (SyncHook): Only synchronous side effects are guaranteed. `process.exit`
 86→ *   follows immediately.
 87→ */
 88→const hooks = {
 89→  loopStart: new AsyncSeriesHook<[typeof CONFIG]>(['config']),
 90→  iterationStart: new AsyncSeriesHook<[IterationContext]>(['context']),
 91→  iterationSuccess: new AsyncSeriesHook<[IterationResult, IterationContext]>([
 92→    'result',
 93→    'context',
 94→  ]),
 95→  iterationTimeout: new AsyncSeriesHook<[IterationResult, IterationContext]>([
 96→    'result',
 97→    'context',
 98→  ]),
 99→  iterationFailure: new AsyncSeriesHook<[IterationResult, FailureContext]>([
100→    'result',
101→    'context',
102→  ]),
103→  resolveStatus: new SyncWaterfallHook<[RalphStatus | null, string]>([
104→    'status',
105→    'output',
106→  ]),
107→  taskComplete: new AsyncSeriesHook<[RalphStatus, IterationContext]>([
108→    'status',
109→    'context',
110→  ]),
111→  allTasksComplete: new AsyncSeriesHook<[RalphStatus, number]>([
112→    'status',
113→    'totalIterations',
114→  ]),
115→  shouldSkipBackoff: new SyncBailHook<[BackoffContext], boolean | undefined>([
116→    'context',
117→  ]),
118→  loopEnd: new AsyncSeriesHook<[number]>(['totalIterations']),
119→  cleanup: new SyncHook<[string]>(['signal']),
120→};
121→
122→export { hooks as ralphHooks };
123→
124→function slugify(text: string): string {
125→  return text
126→    .toLowerCase()
127→    .normalize('NFD')
128→    .replace(/[\u0300-\u036f]/g, '')
129→    .replace(/[^a-z0-9]+/g, '-')
130→    .replace(/^-+|-+$/g, '')
131→    .slice(0, 60);
132→}
133→
134→function logTimestamp(): string {
135→  const d = new Date();
136→  return `${d.toISOString().slice(0, 10)}_${d.toISOString().slice(11, 19).replace(/:/g, '')}`;
137→}
138→
139→function logFilePath(slug: string): string {
140→  return `${LOG_DIR}/${logTimestamp()}_${slug}.log`;
141→}
142→
143→class LogBuffer {
144→  private buf: string[] = [];
145→  private timer: ReturnType<typeof setInterval> | null = null;
146→  private path: string;
147→
148→  constructor(
149→    initialPath: string,
150→    private readonly flushMs: number,
151→  ) {
152→    this.path = initialPath;
153→    this.timer = setInterval(() => this.flush(), this.flushMs);
154→    if (this.timer && typeof this.timer === 'object' && 'unref' in this.timer) {
155→      (this.timer as NodeJS.Timeout).unref();
156→    }
157→  }
158→
159→  write(raw: string): void {
160→    this.buf.push(stripAnsi(raw));
161→  }
162→
163→  flush(): void {
164→    if (this.buf.length === 0) return;
165→    const chunk = this.buf.join('');
166→    this.buf.length = 0;
167→    try {
168→      appendFileSync(this.path, chunk);
169→    } catch (err) {
170→      console.error(`[LogBuffer] write failed: ${err}`);
171→    }
172→  }
173→
174→  startNewFile(newPath: string): void {
175→    this.flush();
176→    this.path = newPath;
177→  }
178→
179→  renameFile(newPath: string): void {
180→    this.flush();
181→    try {
182→      renameSync(this.path, newPath);
183→      this.path = newPath;
184→    } catch {}
185→  }
186→
187→  currentPath(): string {
188→    return this.path;
189→  }
190→
191→  dispose(): void {
192→    if (this.timer) clearInterval(this.timer);
193→    this.flush();
194→  }
195→}
196→
197→const logBuffer = new LogBuffer(
198→  logFilePath('startup'),
199→  CONFIG.logFlushInterval,
200→);
201→
202→type Color = 'green' | 'yellow' | 'red' | 'blue' | 'blackBright';
203→
204→function print(message: string, color?: Color): void {
205→  const colored = color ? chalk[color](message) : message;
206→  process.stdout.write(colored);
207→  logBuffer.write(message);
208→}
209→
210→function println(message = '', color?: Color): void {
211→  const ts = new Date().toISOString().replace('T', ' ').slice(0, 19);
212→  print(`[${ts}] ${message}\n`, color);
213→}
214→
215→function syslog(message = '', color?: Color): void {
216→  println(`‣ ${message}`, color);
217→}
218→
219→async function callHookSafe(
220→  hook: { promise: (...args: never[]) => Promise<void> },
221→  name: string,
222→  ...args: unknown[]
223→): Promise<void> {
224→  try {
225→    await (hook.promise as (...a: unknown[]) => Promise<void>)(...args);
226→  } catch (err) {
227→    syslog(`Hook "${name}" error: ${err}`, 'red');
228→  }
229→}
230→
