269→- No task should be submitted as "look reasonable."
270→- Every task must be delivered with professional quality, without any makeshift solutions.
271→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
272→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
273→- Never trust project comments or documentation without confirming on actual
274→code.
275→
276→--------------------------------------------------------------------------------
277→
278→OUTPUT STATUS (REQUIRED at end of EVERY response):
279→You MUST output this exact format at the END of your response:
280→
281→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
282→
283→Examples:
284→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
285→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
286→
287→`;
288→
289→interface ContentBlock {
290→  type: 'text' | 'tool_use' | 'tool_result';
291→  text?: string;
292→  name?: string;
293→  input?: unknown;
294→  content?:
295→    | string
296→    | Array<{
297→        type: string;
298→        text?: string;
299→      }>;
300→}
301→
302→interface StreamMessage {
303→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
304→  subtype?: string;
305→  role?: 'assistant' | 'user';
306→  event?: {
307→    type: string;
308→    delta?: {
309→      type: string;
310→      text?: string;
311→    };
312→  };
313→  result?: string;
314→  message?: {
315→    role?: string;
316→    content?: ContentBlock[];
317→  };
318→  content?: ContentBlock[];
319→}
320→
321→function parseRalphStatus(output: string): RalphStatus | null {
322→  const marker = output.lastIndexOf('RALPH_STATUS:');
323→  if (marker === -1) return null;
324→
325→  const jsonStart = output.indexOf('{', marker);
326→  if (jsonStart === -1) return null;
327→
328→  let depth = 0;
329→  for (let i = jsonStart; i < output.length; i++) {
330→    if (output[i] === '{') depth++;
331→    if (output[i] === '}') depth--;
332→    if (depth === 0) {
333→      try {
334→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
335→        if (typeof parsed.exit === 'boolean') {
336→          return parsed as RalphStatus;
337→        }
338→      } catch {}
339→      return null;
340→    }
341→  }
342→  return null;
343→}
344→
345→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
346→
347→function killCurrentProc(): void {
348→  if (!currentProc) return;
349→  try {
350→    currentProc.kill();
351→  } catch {}
352→}
353→
354→async function checkDependencies(): Promise<void> {
355→  const result = await Bun.$`which claude`.quiet().nothrow();
356→  if (result.exitCode !== 0) {
357→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
358→    process.exit(1);
359→  }
360→
361→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
362→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
363→    process.exit(1);
364→  }
365→}
366→
367→async function runIteration(): Promise<IterationResult> {
368→  syslog('Executing Claude Code...');
369→
370→  const proc = Bun.spawn(
371→    [
372→      'claude',
373→      '-p',
374→      TASK_PROMPT,
375→      '--verbose',
376→      '--debug',
377→      '--dangerously-skip-permissions',
378→      '--output-format',
379→      'stream-json',
380→      '--include-partial-messages',
381→      '--model=opus',
382→    ],
383→    {
384→      cwd: process.cwd(),
385→      env: process.env,
386→      stdout: 'pipe',
387→      stderr: 'inherit',
388→    },
389→  );
390→
391→  currentProc = proc;
392→
393→  const chunks: string[] = [];
394→  let timedOut = false;
395→  const decoder = new TextDecoder();
396→  let buffer = '';
397→  let blockHasContent = false;
398→
399→  const timeoutId = setTimeout(() => {
400→    timedOut = true;
401→    syslog('Iteration timeout reached. Killing process...', 'yellow');
402→    killCurrentProc();
403→  }, CONFIG.iterationTimeout);
404→
405→  const reader = proc.stdout.getReader();
406→
407→  try {
408→    while (true) {
409→      const { done, value } = await reader.read();
410→      if (done) break;
411→
412→      buffer += decoder.decode(value, { stream: true });
413→
414→      const lines = buffer.split('\n');
415→      buffer = lines.pop() || '';
416→
417→      for (const line of lines) {
418→        if (!line.trim()) continue;
419→
420→        let msg: StreamMessage;
421→        try {
422→          msg = JSON.parse(line);
423→        } catch {
424→          continue;
425→        }
426→
427→        if (msg.type === 'stream_event') {
428→          const evt = msg.event;
429→          if (!evt) continue;
430→
431→          if (evt.type === 'content_block_start') {
432→            blockHasContent = false;
433→          } else if (evt.type === 'content_block_delta') {
434→            const text = evt.delta?.text;
435→            if (text) {
436→              print(text);
437→              chunks.push(text);
438→              blockHasContent = true;
439→            }
440→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
441→            print('\n');
442→            chunks.push('\n');
443→            blockHasContent = false;
444→          }
445→          continue;
446→        }
447→
448→        if (msg.type === 'assistant' || msg.type === 'message') {
449→          const blocks = msg.message?.content ?? msg.content;
450→          if (!Array.isArray(blocks)) continue;
451→
452→          for (const block of blocks) {
453→            if (block.type === 'text' && block.text && chunks.length === 0) {
454→              print(block.text);
455→              chunks.push(block.text);
456→              print('\n');
457→              chunks.push('\n');
458→            }
459→          }
460→          continue;
461→        }
462→
463→        if (msg.type === 'user') {
464→          const blocks = msg.message?.content ?? msg.content;
465→          if (!Array.isArray(blocks)) continue;
466→
467→          for (const block of blocks) {
468→            if (block.type === 'tool_result' && block.content) {
469→              const rawContent =
470→                typeof block.content === 'string'
471→                  ? block.content
472→                  : block.content
473→                      .map(c => c.text ?? '')
474→                      .filter(Boolean)
475→                      .join('\n');
476→
477→              if (!rawContent) continue;
478→
479→              let trimmed = rawContent.trim().slice(0, 320);
480→
481→              const toolResult =
482→                trimmed && trimmed !== rawContent
483→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
484→                  : rawContent;
485→
486→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
487→              chunks.push('\n', rawContent, '\n');
488→            }
489→          }
490→          continue;
491→        }
492→
493→        if (msg.type === 'result' && msg.result) {
494→          if (chunks.length === 0) {
495→            chunks.push(msg.result);
496→          }
497→        }
498→      }
499→    }
500→
501→    if (buffer.trim()) {
502→      try {
503→        const msg: StreamMessage = JSON.parse(buffer);
504→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
505→          chunks.push(msg.result);
506→        }
507→      } catch {}
508→    }
509→  } finally {
510→    clearTimeout(timeoutId);
511→    reader.releaseLock();
512→    currentProc = null;
513→    logBuffer.flush();
514→  }
515→
516→  const output = chunks.join('');
517→
518→  if (timedOut) {
519→    return {
520→      output,
521→      exitCode: 124,
522→      timedOut: true,
523→    };
524→  }
525→
526→  const exitCode = await proc.exited;
527→  println();
528→  return {
529→    output,
530→    exitCode,
531→    timedOut: false,
532→  };
533→}
534→
535→function printHeader(): void {
536→  println();
537→  println('==========================================', 'blue');
538→  println('   Ralph Loop - Bun.js Edition', 'blue');
539→  println('==========================================', 'blue');
540→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
541→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
542→  println(
543→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
544→  );
545→  println(
546→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
547→  );
548→  println();
549→}
550→
551→async function main(): Promise<void> {
552→  let cleanupCalled = false;
553→
554→  const cleanup = (signal: string) => {
555→    if (cleanupCalled) return;
556→    cleanupCalled = true;
557→    try {
558→      hooks.cleanup.call(signal);
559→    } catch (err) {
560→      console.error(`[cleanup hook error] ${err}`);
561→    }
562→    println();
563→    syslog(`Interrupted by ${signal}. Cleaning up...`);
564→    killCurrentProc();
565→    logBuffer.dispose();
566→    process.exit(signal === 'SIGINT' ? 130 : 143);
567→  };
568→
569→  process.on('SIGINT', () => cleanup('SIGINT'));
570→  process.on('SIGTERM', () => cleanup('SIGTERM'));
571→
572→  await checkDependencies();
573→
574→  printHeader();
575→  syslog('Starting automated task loop...');
576→
577→  await hooks.loopStart.promise(CONFIG);
578→
579→  let consecutiveFailures = 0;
580→  let iteration = 0;
581→  const BACKOFF_BASE_MS = 60_000;
582→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
583→
584→  while (iteration < CONFIG.maxIterations) {
585→    const attemptNum = iteration + 1;
586→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
587→
588→    const iterCtx: IterationContext = {
589→      iteration: attemptNum,
590→      maxIterations: CONFIG.maxIterations,
591→      logPath: logBuffer.currentPath(),
592→    };
593→
594→    println();
595→    println('==========================================', 'green');
596→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
597→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
598→    println('==========================================', 'green');
599→    println();
600→
601→    await callHookSafe(hooks.iterationStart, 'iterationStart', iterCtx);
602→
603→    const result = await runIteration();
604→    const { output, exitCode, timedOut } = result;
605→
606→    if (exitCode === 0) {
607→      syslog('Claude Code completed successfully', 'green');
608→      consecutiveFailures = 0;
609→      await callHookSafe(
610→        hooks.iterationSuccess,
611→        'iterationSuccess',
612→        result,
613→        iterCtx,
614→      );
615→    } else if (timedOut) {
616→      syslog(
617→        'Iteration timed out — progress may persist in progress.txt',
618→        'yellow',
619→      );
620→      consecutiveFailures = 0;
621→      await callHookSafe(
622→        hooks.iterationTimeout,
623→        'iterationTimeout',
624→        result,
625→        iterCtx,
626→      );
627→    } else {
628→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
629→      consecutiveFailures++;
630→
631→      const failCtx: FailureContext = {
632→        ...iterCtx,
633→        exitCode,
634→        consecutiveFailures,
635→      };
636→      await callHookSafe(
637→        hooks.iterationFailure,
638→        'iterationFailure',
639→        result,
640→        failCtx,
641→      );
642→
643→      const backoffMs = Math.min(
644→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
645→        BACKOFF_MAX_MS,
646→      );
647→      const backoffMin = (backoffMs / 60_000).toFixed(1);
648→
649→      const backoffCtx: BackoffContext = { ...failCtx, backoffMs };
650→      let skipBackoff: boolean | undefined;
651→      try {
652→        skipBackoff = hooks.shouldSkipBackoff.call(backoffCtx);
653→      } catch (err) {
654→        syslog(`Hook "shouldSkipBackoff" error: ${err}`, 'red');
655→      }
656→
657→      if (skipBackoff === true) {
658→        syslog('Backoff skipped by hook', 'yellow');
659→      } else {
660→        println();
661→        println('==========================================', 'yellow');
662→        syslog(
663→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
664→          'yellow',
665→        );
666→        println('==========================================', 'yellow');
667→        await Bun.sleep(backoffCtx.backoffMs);
668→      }
669→      continue;
670→    }
671→
672→    iteration++;
673→
674→    const rawStatus = parseRalphStatus(output);
675→    let status: RalphStatus | null;
676→    try {
677→      status = hooks.resolveStatus.call(rawStatus, output);
678→    } catch (err) {
679→      syslog(`Hook "resolveStatus" error: ${err}`, 'red');
680→      status = rawStatus;
681→    }
682→    const taskSlug = status
683→      ? slugify(status.task)
684→      : timedOut
685→        ? 'timeout'
686→        : 'no-status';
687→    logBuffer.renameFile(logFilePath(taskSlug));
688→
689→    if (status?.exit) {
690→      await callHookSafe(
691→        hooks.allTasksComplete,
692→        'allTasksComplete',
693→        status,
694→        iteration,
695→      );
696→      println();
697→      println('==========================================', 'green');
698→      syslog('ALL TASKS COMPLETED!', 'green');
699→      syslog(`Final task:      ${status.task}`, 'green');
700→      syslog(`Remaining:       ${status.remaining}`, 'green');
701→      syslog(`Total iterations: ${iteration}`, 'green');
702→      println('==========================================', 'green');
703→      logBuffer.dispose();
704→      process.exit(0);
705→    }
706→
707→    if (status) {
708→      await callHookSafe(
709→        hooks.taskComplete,
710→        'taskComplete',
711→        status,
712→        iterCtx,
713→      );
714→      syslog(
715→        `Task done: "${status.task}" — ${status.remaining} remaining`,
716→        'blue',
717→      );
718→    } else if (!timedOut && exitCode === 0) {
719→      syslog(
720→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
721→        'yellow',
722→      );
723→    }
724→
725→    if (iteration < CONFIG.maxIterations) {
726→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
727→      println();
728→      syslog(`Waiting ${delaySec}s before next iteration...`);
729→      await Bun.sleep(CONFIG.delayBetweenIterations);
730→    }
731→  }
732→
733→  await callHookSafe(hooks.loopEnd, 'loopEnd', iteration);
734→
735→  println();
736→  println('==========================================', 'red');
737→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
738→  syslog('Loop stopped — tasks may still be pending', 'red');
739→  println('==========================================', 'red');
740→  logBuffer.dispose();
741→  process.exit(1);
742→}
743→
744→if (import.meta.main) {
745→  main();
746→}
