137→  write(raw: string): void {
138→    this.buf.push(stripAnsi(raw));
139→  }
140→
141→  flush(): void {
142→    if (this.buf.length === 0) return;
143→    const chunk = this.buf.join('');
144→    this.buf.length = 0;
145→    try {
146→      appendFileSync(this.path, chunk);
147→    } catch (err) {
148→      console.error(`[LogBuffer] write failed: ${err}`);
149→    }
150→  }
