347→async function runIteration(): Promise<IterationResult> {
348→  syslog('Executing Claude Code...');
349→
350→  const proc = Bun.spawn(
351→    [
352→      'claude',
353→      '-p',
354→      TASK_PROMPT,
355→      '--verbose',
356→      '--debug',
357→      '--dangerously-skip-permissions',
358→      '--output-format',
359→      'stream-json',
360→      '--include-partial-messages',
361→      '--model=opus',
362→    ],
363→    {
364→      cwd: process.cwd(),
365→      env: process.env,
366→      stdout: 'pipe',
367→      stderr: 'inherit',
368→    },
369→  );
