48→export type EarlyPluginResult = {
49→  fulfilled: true;
50→  value: any;
51→};
52→
53→export function isEarlyPluginResult(input: any): input is EarlyPluginResult {
54→  return (
55→    input &&
56→    typeof input === 'object' &&
57→    input.fulfilled === true &&
58→    input.hasOwnProperty?.('value')
59→  );
60→}
