  8→
  9→export const EmptySymbol = Symbol('EmptySymbol');
 10→export type EmptySymbol = typeof EmptySymbol & {};
 11→
 12→export type AsyncPluginMiddleware<T, C> = {
 13→  (
 14→    this: PluginExecutionContext<T, C>,
 15→    currentValue: T,
 16→    context: C,
 17→    pluginExecutionContext: PluginExecutionContext<T, C>
 18→  ): Promise<T | EmptySymbol | void> | T | EmptySymbol | void;
 19→};
 20→
 21→export interface AsyncPluginRegister<T, C> {
 22→  (name: string, middleware: AsyncPluginMiddleware<T, C>): PluginRegisterInfo<T, C>;
 23→  (middleware: AsyncPluginMiddleware<T, C>): PluginRegisterInfo<T, C>;
 24→}
 25→
 26→export type AsyncExec<T, C = never> = IsKnown<C> extends 1
 27→  ? [C] extends [undefined]
 28→    ? (initialValue: T, context?: C) => Promise<T>
 29→    : (initialValue: T, context: C) => Promise<T>
 30→  : (initialValue: T, context?: C) => Promise<T>;
 31→
 32→export interface AsyncPlugin<T, C> extends AsyncPluginRegister<T, C> {
 33→  dispatch: AsyncExec<T, C>;
 34→  pushMiddleware: AsyncPluginRegister<T, C>;
 35→  unshiftMiddleware: AsyncPluginRegister<T, C>;
 36→  middlewares: AsyncPluginMiddleware<T, C>[];
 37→}
 38→
 39→export type CreateAsyncPlugin = {
 40→  <T, C = undefined>(options?: PluginOptions<T, C>): AsyncPlugin<T, C>;
 41→};
 42→
 43→export const createAsyncPlugin: CreateAsyncPlugin = function <T, C>(
 44→  options: PluginOptions<T, C> = {}
 45→) {
 46→  const middlewares: AsyncPluginMiddleware<T, C>[] = [];
 47→
 48→  const { returnOnFirst } = options;
 49→
 50→  let canAddNew = true;
 51→
 52→  function addMiddleware(position: 'push' | 'unshift'): AsyncPluginRegister<T, C> {
 53→    return function addMiddleware(...args: any) {
 54→      const { middleware, name } = (() => {
 55→        if (typeof args[0] === 'string') {
 56→          const customName = args[0];
 57→
 58→          const mid = args[1] as AsyncPluginMiddleware<T, C>;
 59→          if (typeof mid !== 'function') throw new TypeError('Expected args[1] to be a function.');
 60→
 61→          try {
 62→            Object.defineProperty(mid, 'name', { value: customName });
 63→          } catch (e) {}
 64→
 65→          return { name: customName, middleware: mid };
 66→        }
 67→
 68→        const mid = args[0];
 69→        if (typeof mid !== 'function') throw new TypeError('Expected args[0] to be a function.');
 70→        return { name: 'unnamed_middleware', middleware: mid as AsyncPluginMiddleware<T, C> };
 71→      })();
 72→
 73→      middlewares[position](middleware);
 74→
 75→      return {
 76→        name,
 77→        existing: middlewares,
 78→      };
 79→    };
 80→  }
 81→
 82→  const dispatch: AsyncExec<any, any> = async function dispatchAsync(
 83→    initial: T,
 84→    context: C
 85→  ): Promise<T> {
 86→    initial = await initial;
 87→
 88→    if (canAddNew) {
 89→      canAddNew = false;
 90→      Object.freeze(middlewares);
 91→    }
 92→
 93→    const ForceFinishSymbol = Symbol('FORCE_FINISH');
 94→    const ExitMiddlewareSymbol = Symbol('ExitMiddlewareSymbol');
 95→
 96→    let forceFinishedValue: typeof ForceFinishSymbol | T = ForceFinishSymbol;
 97→
 98→    let ignoredCount = middlewares.length;
 99→    let handledCount = 0;
100→    let finished = false;
101→    let lastValue: T | EmptySymbol = initial;
102→
103→    const allMiddlewareContext: PluginExecutionContext<T, C>[] = [];
104→
105→    function onFinish(error: Error | null, result: T | EmptySymbol) {
106→      if (finished) return;
107→      finished = true;
108→      lastValue = result;
109→
110→      allMiddlewareContext.forEach((item) => {
111→        item.finished = true;
112→        item.finishedValue = lastValue;
113→        item.finishedError = error;
114→        item.ignoredCount = ignoredCount;
115→        item.handledCount = handledCount;
116→      });
117→    }
118→
119→    try {
120→      lastValue = await middlewares.reduce(async (_value, middleware, index) => {
121→        const awaited = await _value;
122→
123→        let registeredGlobalCount = false;
124→
125→        function count() {
126→          if (registeredGlobalCount) return;
127→          registeredGlobalCount = true;
128→          handledCount += 1;
129→          ignoredCount -= 1;
130→        }
131→
132→        let replacedValue: T | EmptySymbol = EmptySymbol;
133→        const ReplaceSymbol = Symbol('REPLACE');
134→
135→        const self: PluginExecutionContext<T, C> = {
136→          IgnoredSymbol: EmptySymbol as EmptySymbol,
137→          ignoredCount,
138→          handledCount,
139→          index,
140→          existing: middlewares,
141→          finish,
142→          error: null,
143→          finished,
144→          finishedValue: awaited,
145→          finishedError: null,
146→          exit() {
147→            throw ExitMiddlewareSymbol;
148→          },
149→          replace(value: T) {
150→            count();
151→
152→            replacedValue = value as T;
153→
154→            if (returnOnFirst) {
155→              finish(replacedValue);
156→            } else {
157→              throw ReplaceSymbol;
158→            }
159→          },
160→        };
161→
162→        allMiddlewareContext.push(self);
163→
164→        function finish(value: T) {
165→          forceFinishedValue = value as T;
166→          throw ForceFinishSymbol;
167→        }
168→
169→        try {
170→          lastValue = await (async (current): Promise<T> => {
171→            const returnedValue = await middleware.call(self, current, context, self);
172→
173→            if (returnedValue !== undefined && returnedValue !== EmptySymbol) {
174→              self.replace(returnedValue);
175→              count();
176→              return returnedValue;
177→            } else {
178→              return current;
179→            }
180→          })(awaited);
181→
182→          if (replacedValue !== EmptySymbol) {
183→            if (returnOnFirst) {
184→              finish(lastValue);
185→            }
186→          }
187→
188→          return lastValue;
189→        } catch (e: any) {
190→          if (e === ExitMiddlewareSymbol) {
191→            count();
192→            return lastValue === EmptySymbol ? awaited : lastValue;
193→          }
194→
195→          //
196→          if (e === ReplaceSymbol) {
197→            const value = replacedValue as unknown as T;
198→            count();
199→            return (lastValue = value);
200→          }
201→
202→          if (e === ForceFinishSymbol) {
203→            count();
204→            throw ForceFinishSymbol;
205→          }
206→
207→          onFinish(e, EmptySymbol);
208→          throw e;
209→        }
210→      }, Promise.resolve(initial));
211→    } catch (e: any) {
212→      if (e === ForceFinishSymbol) {
213→        const value = forceFinishedValue as unknown as T;
214→        onFinish(null, value);
215→        return value;
216→      }
217→
218→      if (isEarlyPluginResult(e)) {
219→        const value = e.value as unknown as T;
220→
221→        onFinish(null, value);
222→        return value;
223→      }
224→
225→      onFinish(e, EmptySymbol);
226→      throw e;
227→    }
228→
229→    onFinish(null, lastValue);
230→
231→    return lastValue;
232→  };
233→
234→  const push = addMiddleware('push');
235→  const unshift = addMiddleware('unshift');
236→
237→  const plugin = function asyncPlugin(this: any, ...args: any) {
238→    return push.apply(this, args);
239→  } as AsyncPlugin<T, C>;
240→
241→  plugin.dispatch = dispatch;
242→  plugin.middlewares = middlewares;
243→  plugin.pushMiddleware = push;
244→  plugin.unshiftMiddleware = unshift;
245→
246→  return plugin;
247→};
