  5→export type SyncPluginMiddleware<T, C> = {
  6→  (
  7→    this: PluginExecutionContext<T, C>,
  8→    param: T,
  9→    context: C,
 10→    pluginExecutionContext: PluginExecutionContext<T, C>
 11→  ): void;
 12→};
 13→
 14→// returns a promise with the first middleware return
 15→export interface SyncPluginRegister<T, C> {
 16→  (middleware: SyncPluginMiddleware<T, C>): PluginRegisterInfo<T, C>;
 17→  (name: string, middleware: SyncPluginMiddleware<T, C>): PluginRegisterInfo<T, C>;
 18→}
 19→
 20→export type SyncPluginExec<T, C = never> = IsKnown<C> extends 1
 21→  ? [C] extends [undefined]
 22→    ? (initialValue: T, context?: C) => void
 23→    : (initialValue: T, context: C) => void
 24→  : (initialValue: T, context?: C) => void;
 25→
 26→export interface SyncPlugin<T, C> extends SyncPluginRegister<T, C> {
 27→  dispatch: SyncPluginExec<T, C>;
 28→  pushMiddleware: SyncPluginRegister<T, C>;
 29→  unshiftMiddleware: SyncPluginRegister<T, C>;
 30→  middlewares: SyncPluginMiddleware<T, C>[];
 31→}
 32→
 33→export type CreateSyncPlugin = {
 34→  <T, C = undefined>(options?: PluginOptions<T, C>): SyncPlugin<T, C>;
 35→};
 36→
 37→export const createSyncPlugin: CreateSyncPlugin = function <T, C>(
 38→  options: PluginOptions<T, C> = {}
 39→) {
 40→  const { returnOnFirst } = options;
 41→
 42→  const middlewares: SyncPluginMiddleware<T, C>[] = [];
 43→
 44→  const addMiddleware = function registerSyncPlugin(
 45→    position: 'push' | 'unshift'
 46→  ): SyncPluginRegister<T, C> {
 47→    return function addMiddleware(...args: any[]) {
 48→      const { middleware, name } = (() => {
 49→        if (typeof args[0] === 'string') {
 50→          const customName = args[0];
 51→
 52→          const mid = args[1] as SyncPluginMiddleware<T, C>;
 53→          if (typeof mid !== 'function') throw new TypeError('Expected args[1] to be a function.');
 54→
 55→          try {
 56→            Object.defineProperty(mid, 'name', { value: customName });
 57→          } catch (e) {}
 58→
 59→          return { name: customName, middleware: mid };
 60→        }
 61→
 62→        const mid = args[0];
 63→        if (typeof mid !== 'function') throw new TypeError('Expected args[0] to be a function.');
 64→        return { name: 'unnamed_middleware', middleware: mid as SyncPluginMiddleware<T, C> };
 65→      })();
 66→
 67→      middlewares[position](middleware);
 68→
 69→      return {
 70→        name,
 71→        existing: middlewares,
 72→      };
 73→    };
 74→  };
 75→
 76→  const dispatch: SyncPluginExec<any, any> = function dispatchSync(value: T, context: C) {
 77→    const ForceFinishSymbol = Symbol('FORCE_FINISH');
 78→    const ReplaceSymbol = Symbol('ReplaceSymbol');
 79→    const ExitMiddlewareSymbol = Symbol('ExitMiddlewareSymbol');
 80→
 81→    type ForceFinishSymbol = typeof ForceFinishSymbol;
 82→
 83→    let forceFinishedValue: T | ForceFinishSymbol = ForceFinishSymbol;
 84→
 85→    let lastValue: T | EmptySymbol = value;
 86→    let ignoredCount = middlewares.length;
 87→    let handledCount = 0;
 88→
 89→    const allMiddlewareContext: PluginExecutionContext<T, C>[] = [];
 90→
 91→    let finished = false;
 92→    function onFinish(error: Error | null, result: T | EmptySymbol) {
 93→      if (finished) return;
 94→      finished = true;
 95→
 96→      allMiddlewareContext.forEach((item) => {
 97→        item.finished = true;
 98→        item.finishedValue = result;
 99→        item.finishedError = error;
100→        item.ignoredCount = ignoredCount;
101→        item.handledCount = handledCount;
102→      });
103→    }
104→
105→    try {
106→      middlewares.forEach((middleware, index) => {
107→        let registeredGlobalCount = false;
108→
109→        function count() {
110→          if (registeredGlobalCount) return;
111→          registeredGlobalCount = true;
112→          handledCount += 1;
113→          ignoredCount -= 1;
114→        }
115→
116→        function finish(result: T | EmptySymbol) {
117→          forceFinishedValue = result as T;
118→          throw ForceFinishSymbol;
119→        }
120→
121→        const self: PluginExecutionContext<any, any> = {
122→          IgnoredSymbol: EmptySymbol as EmptySymbol,
123→          handledCount: 0,
124→          ignoredCount: 0,
125→          index,
126→          existing: middlewares,
127→          finish,
128→          finished: false,
129→          finishedError: null,
130→          finishedValue: value,
131→          error: null,
132→          exit() {
133→            throw ExitMiddlewareSymbol;
134→          },
135→          replace(value) {
136→            lastValue = value;
137→            throw ReplaceSymbol;
138→          },
139→        };
140→
141→        allMiddlewareContext.push(self);
142→
143→        try {
144→          if (lastValue !== EmptySymbol && lastValue !== undefined) {
145→            middleware.call(self, lastValue, context, self);
146→            count();
147→          }
148→        } catch (e: any) {
149→          if (e === ExitMiddlewareSymbol) {
150→            count();
151→            return lastValue === EmptySymbol ? value : lastValue;
152→          }
153→
154→          if (e === ReplaceSymbol) {
155→            const value = lastValue as unknown as T;
156→            count();
157→            return (lastValue = value);
158→          }
159→
160→          if (e === ForceFinishSymbol) {
161→            count();
162→            throw ForceFinishSymbol;
163→          }
164→
165→          onFinish(e, EmptySymbol);
166→          throw e;
167→        }
168→
169→        if (returnOnFirst) {
170→          finish(lastValue);
171→        }
172→      });
173→    } catch (e) {
174→      if (e === ForceFinishSymbol) {
175→        lastValue = forceFinishedValue as unknown as T;
176→        onFinish(null, lastValue);
177→      } else {
178→        onFinish(e as Error, EmptySymbol);
179→        throw e;
180→      }
181→    }
182→
183→    onFinish(null, lastValue);
184→  };
185→
186→  const push = addMiddleware('push');
187→  const unshift = addMiddleware('unshift');
188→
189→  const plugin = function syncPlugin(this: any, ...args: any) {
190→    return push.apply(this, args);
191→  } as SyncPlugin<T, C>;
192→
193→  plugin.dispatch = dispatch;
194→  plugin.middlewares = middlewares;
195→  plugin.pushMiddleware = push;
196→  plugin.unshiftMiddleware = unshift;
197→
198→  return plugin;
199→};
